toolArgs.file_text:
@using static sv_d157fb9c2cb64951a980033e77098494.Helpers.TimeFormatter

<div class="message-bubble" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadSummary.Value.ReplyCount @(ThreadSummary.Value.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>
        <EmojiPicker Visible="showEmojiPicker" OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public (int ReplyCount, DateTime LastReplyAt)? ThreadSummary { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter, EditorRequired] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private void ShowActions() => showActions = true;

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }
}

