}

.author {
    font-weight: 700;
    color: #e0e0e0;
    font-size: 0.9rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    color: #dcddde;
    font-size: 0.9rem;
    line-height: 1.4;
    word-wrap: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    background: #2f3136;
    border: 1px solid #3a3f4b;
    border-radius: 4px;
    padding: 2px 8px;
    font-size: 0.8rem;
    color: #dcddde;
    cursor: default;
}

.thread-link {
    background: none;
    border: none;
    color: #5865f2;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #3a3f4b;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.message-actions button {
    background: none;
    border: none;
    color: #b9bbbe;
    padding: 4px 8px;
    cursor: pointer;
    font-size: 0.8rem;
    border-radius: 3px;
    white-space: nowrap;
}

.message-actions button:hover {
    background: #3a3f4b;
    color: #fff;
}

