arguments.file_text:
@page "/chat"
@using sv_d157fb9c2cb64951a980033e77098494.Services
@using sv_d157fb9c2cb64951a980033e77098494.Components.Chat
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-container">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannelAsync" />
    </div>

    <div class="main-container">
        @if (selectedChannel is not null)
        {
            <div class="channel-header">
                <h2># @selectedChannel.Name</h2>
                <span class="channel-description">@selectedChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var message in messages.Where(m => m.ReplyToId is null))
                {
                    <MessageBubble Message="message"
                                   ThreadSummary="GetThreadSummary(message.Id)"
                                   OnOpenThread="OpenThreadAsync"
                                   OnReact="ReactAsync" />
                }
            </div>

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")"
                          ButtonText="Send"
                          OnSubmit="SendMessageAsync" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (activeThreadRootId.HasValue && threadRootMessage is not null)
    {
        <div class="thread-container">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnReply="SendThreadReplyAsync" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadReplies = [];
    private int? selectedChannelId;
    private int? activeThreadRootId;
    private Message? threadRootMessage;
    private bool isLoadingMore;
    private int messageSkip;
    private const int PageSize = 50;

    private ElementReference messageListRef;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<ChatPage>? dotNetRef;

    private Channel? selectedChannel => channels.FirstOrDefault(c => c.Id == selectedChannelId);

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/ChatPage.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        if (selectedChannelId == channelId) return;

        selectedChannelId = channelId;
        messageSkip = 0;
        activeThreadRootId = null;
        threadRootMessage = null;
        threadReplies = [];

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messageSkip = messages.Count;

        await ChatService.MarkChannelReadAsync(channelId);

        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }

        StateHasChanged();
        await InitScrollAsync();
    }

    private async Task InitScrollAsync()
    {
        await Task.Yield();
        if (jsModule is not null && dotNetRef is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
                await jsModule.InvokeVoidAsync("initScrollDetection", messageListRef, dotNetRef);
            }
            catch (JSException) { }
        }
    }

    [JSInvokable]
    public async Task LoadMoreMessages()
    {
        if (isLoadingMore || selectedChannelId is null) return;

        isLoadingMore = true;
        StateHasChanged();

        double previousScrollHeight = 0;
        if (jsModule is not null)
        {
            previousScrollHeight = await jsModule.InvokeAsync<double>("getScrollHeight", messageListRef);
        }

        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            messageSkip += older.Count;
        }

        isLoadingMore = false;
        StateHasChanged();

        if (jsModule is not null && previousScrollHeight > 0)
        {
            await Task.Yield();
            try
            {
                await jsModule.InvokeVoidAsync("preserveScroll", messageListRef, previousScrollHeight);
            }
            catch (JSException) { }
        }
    }

    private async Task SendMessageAsync(string content)
    {
        if (selectedChannelId is null) return;

        var message = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(message);
        StateHasChanged();

        await Task.Yield();
        if (jsModule is not null)
        {
            try { await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef); }
            catch (JSException) { }
        }
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        activeThreadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread()
    {
        activeThreadRootId = null;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (selectedChannelId is null || activeThreadRootId is null) return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannelId.Value, content, activeThreadRootId.Value);
        threadReplies.Add(reply);
        messages.Add(reply);
    }

    private async Task ReactAsync((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
        UpdateReactionLocally(messages, reaction.MessageId, reaction.Emoji);
        UpdateReactionLocally(threadReplies, reaction.MessageId, reaction.Emoji);
    }

    private static void UpdateReactionLocally(List<Message> messageList, int messageId, string emoji)
    {
        var idx = messageList.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messageList[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);

        if (existing is not null)
        {
            reactions.Remove(existing);
            reactions.Add(new Reaction(emoji, [.. existing.Users, "You"]));
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }

        messageList[idx] = msg with { Reactions = reactions };
    }

    private (int ReplyCount, DateTime LastReplyAt)? GetThreadSummary(int messageId)
    {
        var replies = messages.Where(m => m.ReplyToId == messageId).ToList();
        if (replies.Count == 0) return null;
        return (replies.Count, replies.Max(r => r.SentAt));
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("dispose", messageListRef);
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    background: #23272e;
    color: #dcddde;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    overflow: hidden;
}

.sidebar-container {
    width: 20%;
    min-width: 200px;
    flex-shrink: 0;
}

.main-container {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 0;
}

.thread-container {
    width: 25%;
    min-width: 280px;
    flex-shrink: 0;
}

.channel-header {
    padding: 12px 16px;
    border-bottom: 1px solid #2d3039;
    background: #1e2028;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-description {
    font-size: 0.8rem;
    color: #8b8f97;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #72767d;
    font-size: 0.85rem;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

let scrollHandler = null;

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function initScrollDetection(element, dotNetRef) {
    if (scrollHandler) {
        element.removeEventListener('scroll', scrollHandler);
    }

    let throttled = false;
    scrollHandler = () => {
        if (!throttled && element.scrollTop < 50) {
            throttled = true;
            dotNetRef.invokeMethodAsync('LoadMoreMessages').finally(() => {
                setTimeout(() => { throttled = false; }, 500);
            });
        }
    };
    element.addEventListener('scroll', scrollHandler);
}

export function getScrollHeight(element) {
    return element ? element.scrollHeight : 0;
}

export function preserveScroll(element, previousScrollHeight) {
    if (element) {
        element.scrollTop = element.scrollHeight - previousScrollHeight;
    }
}

export function dispose(element) {
    if (element && scrollHandler) {
        element.removeEventListener('scroll', scrollHandler);
        scrollHandler = null;
    }
}

