.chat-layout {
    display: flex;
    height: 100vh;
    background: #23272e;
    color: #dcddde;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    overflow: hidden;
}

.sidebar-container {
    width: 20%;
    min-width: 200px;
    flex-shrink: 0;
}

.main-container {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 0;
}

.thread-container {
    width: 25%;
    min-width: 280px;
    flex-shrink: 0;
}

