    padding: 12px 16px;
    border-bottom: 1px solid #2d3039;
    background: #1e2028;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-description {
    font-size: 0.8rem;
    color: #8b8f97;
}

.message-list {
    flex: 1;
    overflow-y: auto;
